SELECT fp.id, fp.name, fp.location, fp.description, fp.image, fp.status, fp.apply_status AS applyStatus, fp.show_to_student AS showToStudent, fp.animal_count AS animalCount, fp.today_feed_count AS todayFeedCount, fp.latitude, fp.longitude, fp.submitter_id AS submitterId, COALESCE(fp.submitter_name, u.name, u.username) AS submitterName, fp.create_time AS createTime, fp.update_time AS updateTime FROM feed_point fp LEFT JOIN user u ON fp.submitter_id = u.id
AND fp.name LIKE concat('%', #{name}, '%')
AND fp.apply_status = #{applyStatus}
AND fp.status = #{status}
ORDER BY fp.id DESC
LIMIT #{current}, #{size}

SELECT COUNT(*) FROM feed_point


        AND name LIKE concat('%', #{name}, '%')


        AND apply_status = #{applyStatus}


        AND status = #{status}
